package com.hospital.management.controller.medical;import com.hospital.management.model.*;import com.hospital.management.util.RequestUtil;import javax.servlet.http.*;import java.time.LocalDate;
final class MedicalRequest {private MedicalRequest(){}static AuthenticatedUser user(HttpServletRequest q){HttpSession s=q==null?null:q.getSession(false);Object u=s==null?null:s.getAttribute("authenticatedUser");return u instanceof AuthenticatedUser a?a:null;}static Long id(String v){try{long x=Long.parseLong(v);return x>0?x:null;}catch(Exception e){return null;}}static int number(String v,int d){try{return Integer.parseInt(v);}catch(Exception e){return d;}}static LocalDate date(String v){try{return v==null||v.isBlank()?null:LocalDate.parse(v);}catch(Exception e){return null;}}static MedicalRecordForm form(HttpServletRequest q){MedicalRecordForm f=new MedicalRecordForm();f.setMedicalRecordId(id(q.getParameter("medicalRecordId")));f.setAppointmentId(id(q.getParameter("appointmentId")));f.setSymptoms(q.getParameter("symptoms"));f.setDiagnosis(q.getParameter("diagnosis"));f.setTreatmentNotes(q.getParameter("treatmentNotes"));f.setAllergies(q.getParameter("allergies"));f.setBloodPressure(q.getParameter("bloodPressure"));f.setTemperature(q.getParameter("temperature"));f.setWeight(q.getParameter("weight"));f.setHeight(q.getParameter("height"));return f;}static AuditContext audit(HttpServletRequest q){return RequestUtil.buildAuditContext(q);}}
